parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

// Facebook webhook verification
if (body['hub.mode'] === 'subscribe' && body['hub.verify_token'] === $env.FB_VERIFY_TOKEN) {
  return [{ json: { type: 'verification', challenge: body['hub.challenge'] } }];
}

// Parse incoming message
const entry = (body.entry || [])[0];
if (!entry) return [{ json: { type: 'empty' } }];

const messaging = (entry.messaging || [])[0];
if (!messaging) return [{ json: { type: 'empty' } }];

const senderId = messaging.sender?.id;
const messageText = messaging.message?.text || '';
const isEcho = messaging.message?.is_echo;
const postback = messaging.postback?.title;

// Skip echoes from our own messages
if (isEcho) return [{ json: { type: 'echo_skip' } }];

return [{ json: {
  type: 'message',
  senderId,
  text: messageText,
  postback,
  timestamp: messaging.timestamp,
  pageId: entry.id
}}];

const msg = $input.first().json;
const text = (msg.text || '').toLowerCase().trim();

// Intent classification
let intent = 'general';
let autoReply = null;

const greetings = ['hello', 'hi', 'hey', 'good morning', 'good evening', 'mingalabar'];
const services = ['cctv', 'camera', 'network', 'wifi', 'nas', 'storage', 'install', 'repair', 'maintenance'];
const pricing = ['price', 'cost', 'quote', 'quotation', 'how much', 'rate'];
const schedule = ['schedule', 'book', 'appointment', 'visit', 'come'];
const complaint = ['problem', 'issue', 'broken', 'not working', 'complaint', 'help'];
const status = ['status', 'update', 'job', 'ticket', 'progress'];

if (greetings.some(g => text.includes(g))) {
  intent = 'greeting';
  autoReply = 'Hello! Welcome to Awesome Myanmar. We provide CCTV, Networking, WiFi, and NAS solutions. How can we help you today?';
} else if (pricing.some(p => text.includes(p))) {
  intent = 'pricing';
  autoReply = 'Thank you for your interest! Our pricing depends on your specific requirements. Please share your site details and we will prepare a custom quotation for you.';
} else if (schedule.some(s => text.includes(s))) {
  intent = 'scheduling';
  autoReply = 'We would be happy to schedule a site visit! Please provide:\n1. Your location/address\n2. Preferred date and time\n3. Type of service needed';
} else if (services.some(s => text.includes(s))) {
  intent = 'service_inquiry';
  autoReply = 'We specialize in CCTV, Networking, WiFi Mesh, and NAS Storage systems. Could you tell us more about what you need?';
} else if (complaint.some(c => text.includes(c))) {
  intent = 'complaint';
  autoReply = 'We are sorry to hear you are having issues. Could you please describe the problem in more detail? We will prioritize your request.';
} else if (status.some(s => text.includes(s))) {
  intent = 'status_check';
  autoReply = 'Please provide your Job ID or Client ID and we will check the status for you right away.';
} else if (msg.postback) {
  intent = 'postback';
  if (msg.postback === 'GET_STARTED') {
    autoReply = 'Welcome to Awesome Myanmar! We provide professional CCTV, Networking, and Infrastructure solutions. Choose an option below or type your question.';
  }
}

return [{ json: { ...msg, intent, autoReply } }];

